mapper.insert:
/** CmmtInsiderHistDao.insert */
insert into cmmt_insider_hist (
	hist_id
	,hist_dt
	,member_id
	,worker_id
	,work_cn
) values (
	#{histId}
	,#{histDt}
	,#{memberId}
	,#{workerId}
	,#{workCn}
)

/** CmmtInsiderHistDao.insertList */
