	hist_id
	,hist_dt
	,member_id
	,worker_id
	,work_cn
) values

(
	 #{item.histId}
	,#{item.histDt}
	,#{item.memberId}
	,#{item.workerId}
	,#{item.workCn}
)

mapper.select:
/** CmmtInsiderHistDao.selectCount */
select
	count(member_id) as cnt
from cmmt_insider_hist
where
	member_id = #{memberId}

